<template>
  <view class="page-container">
    <!-- <text class="page-title">康复资源对接</text> -->

    <!-- 筛选栏 -->
    <view class="filter-box">
      <u-dropdown>
        <u-dropdown-item v-model="filterRegion" :options="regionOptions" @change="onFilterChange"></u-dropdown-item>
      </u-dropdown>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading && institutions.length === 0 " class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <view v-else class="content-box">
      <!-- 康复机构名录 -->
      <view class="section">
        <view class="section-header">
          <text class="section-title">康复机构名录</text>
          <u-button size="mini" plain @click="viewAllInstitutions">
            查看全部
          </u-button>
        </view>
        
        <u-cell-group>
          <u-cell
            v-for="item in institutions"
            :key="item.id"
            :title="item.name"
            :label="`${item.region} · ${item.contact}`"
            is-link
            @click="viewDetails(item)"
          >
            <template #value>
              <u-tag v-if="item.isInsurance" text="医保" type="success" size="mini"></u-tag>
            </template>
          </u-cell>
        </u-cell-group>

        <u-loadmore 
          :status="institutionLoadStatus" 
          @loadmore="onInstitutionPageChange"
          v-if="institutions.length > 0"
        />
        <u-empty v-if="!loading && institutions.length === 0" mode="data" description="暂无康复机构"></u-empty>
      </view>

    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 筛选条件
const filterRegion = ref('all')

// 机构分页
const institutionPage = ref(1)
const institutionPageSize = ref(5)
const institutionTotal = ref(0)
const institutionLoadStatus = ref<'loading' | 'loadmore' | 'nomore'>('loadmore')

// 筛选项
const regionOptions = ref<{ text: string; value: string }[]>([])

// 列表数据
const institutions = ref<any[]>([])
const loading = ref(false)

// 获取地区选项
const fetchRegionOptions = async () => {
  try {
    const res = await request.get('/api/resource/rehab/regions')
    const data = res.data || res.data || {}
    if (data.regions && Array.isArray(data.regions)) {
      regionOptions.value = [
        { text: '全部地区', value: 'all' },
        ...data.regions.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    regionOptions.value = [{ text: '全部地区', value: 'all' }]
  }
}



// 获取康复机构列表
const fetchInstitutions = async (isRefresh = false) => {
  if (isRefresh) {
    institutionPage.value = 1
    institutions.value = []
    institutionLoadStatus.value = 'loading'
  }
  
  if (institutionLoadStatus.value === 'nomore' && !isRefresh) return

  loading.value = true
  
  try {
    const params: Record<string, any> = {
      page: institutionPage.value,
      pageSize: institutionPageSize.value
    }
    if (filterRegion.value !== 'all') params.region = filterRegion.value

    const res = await request.get('/api/resource/rehab/institutions', { params })
    const responseData = res.data || res.data || {}
    const records = responseData.list || []
    
    institutions.value.push(...records)
    institutionTotal.value = responseData.total || 0
    
    if (records.length < institutionPageSize.value) {
      institutionLoadStatus.value = 'nomore'
    } else {
      institutionLoadStatus.value = 'loadmore'
      institutionPage.value++
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/RehabResourceList.vue:129','获取康复机构失败:', error)
    uni.showToast({ title: '加载失败', icon: 'none' })
    institutionLoadStatus.value = 'loadmore'
  } finally {
    loading.value = false
  }
}



// 机构分页变化
const onInstitutionPageChange = () => {
  fetchInstitutions()
}



// 筛选变化
const onFilterChange = () => {
  fetchInstitutions(true)
}

// 查看全部机构
const viewAllInstitutions = () => {
  uni.navigateTo({ url: '/pages/resource/rehab/RehabResourceList' })
}

// 查看全部器械
const viewAllDevices = () => {
  uni.navigateTo({ url: '/pages/resource/rehab/RehabResourceList' })
}

// 查看机构详情
const viewDetails = (item: any) => {
  if (!item?.id) {
    uni.showToast({ title: '机构信息不完整', icon: 'none' })
    return
  }
  uni.navigateTo({ url: `/pages/resource/rehab/InstitutionDetail?id=${item.id}` })
}



onMounted(() => {
  fetchRegionOptions()
  fetchInstitutions()
})
</script>

